// src/components/Footer.jsx
import React from "react";
import { Link } from "react-router-dom";

export default function Footer() {
  return (
    <footer style={styles.footer}>
      <div style={styles.container}>
        {/* Left: Contact Info */}
        <div style={styles.column}>
          <h2 style={styles.title}>Sooraj Crop Sciences</h2>
          <p>📍 Lahore, Pakistan</p>
          <p>📞 +92 300 1234567</p>
          <p>✉️ info@soorajcropsciences.com</p>
        </div>

        {/* Center: Navigation Links */}
        <div style={{ ...styles.column, textAlign: "center" }}>
          <h3 style={{ marginBottom: "10px" }}>Quick Links</h3>
          <div style={styles.links}>
            <Link to="/" style={styles.link}>Home</Link>
            <Link to="/about" style={styles.link}>About</Link>
            <Link to="/Products" style={styles.link}>Products</Link>
            <Link to="/contact" style={styles.link}>Contact</Link>
            <Link to="/FAQs" style={styles.link}>FAQs</Link>
          </div>
        </div>

        {/* Right: Map */}
        <div style={styles.column}>
          <h3 style={{ marginBottom: "10px", textAlign: "right" }}>Find Us</h3>
          <iframe
            title="office-map-footer"
            src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d26884.02493846678!2d74.24503060741358!3d31.384411034262236!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x391907eecc85c783%3A0xaa4ebaade9463825!2sSooraj%20Crop%20Sciences!5e1!3m2!1sen!2s!4v1762350948029!5m2!1sen!2s"
            width="100%"
            height="180"
            style={{ border: 0, borderRadius: "10px" }}
            allowFullScreen=""
            loading="lazy"
          ></iframe>
        </div>
      </div>

      {/* Copyright */}
      <div style={styles.bottom}>
        © {new Date().getFullYear()} Sooraj Crop Sciences. All rights reserved.
      </div>
    </footer>
  );
}

// ✅ Inline styles for simplicity — you can move to CSS later
const styles = {
  footer: {
    backgroundColor: "#127a3a",
    color: "white",
    padding: "40px 20px 20px",
    marginTop: "60px",
  },
  container: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(250px, 1fr))",
    gap: "30px",
    alignItems: "start",
    maxWidth: "1100px",
    margin: "0 auto",
  },
  column: {
    display: "flex",
    flexDirection: "column",
    gap: "8px",
  },
  title: {
    marginBottom: "10px",
  },
  links: {
    display: "flex",
    flexDirection: "column",
    gap: "6px",
  },
  link: {
    color: "white",
    textDecoration: "none",
    fontSize: "15px",
    transition: "color 0.2s",
  },
  bottom: {
    textAlign: "center",
    fontSize: "14px",
    marginTop: "30px",
    borderTop: "1px solid rgba(255,255,255,0.3)",
    paddingTop: "15px",
  },
};
